"""
MKT Original — Zechariah chapters 8-13 (91 verses; ch12:10 already exists)
Run: python3 scripts/zc-original-zechariah-8-13.py

Key decisions:
- Zechariah 8 is a string of ten oracles framed by "This is what the LORD of Hosts says"
  (a formula that appears 10 times). Key terms: qanna (jealous/zealous, 8:2), covenant formula
  (my people/their God, 8:8), emet (truth) as the defining civic virtue (8:3, 16, 19).
- Zechariah 9-14 is "Second Zechariah" (chs. 9-14, undated), stylistically distinct from 1-8.
  Ch. 9:9 (triumphal entry) is the pivotal verse; MT reads tsaddiq wenoshia (righteous and
  having-salvation, passive Niphal) — the king is himself righteous and is-being-saved by YHWH,
  not the one actively saving — this is the rarer, theologically richer reading.
- 11:12-13: sheloshim keseph (thirty pieces of silver) + yotzer (potter/treasury) — the
  Hebrew yotzer and otzar (treasury) are very similar; LXX and NT both use "treasury."
- 12:10: the "me ... him" shift — YHWH speaking of himself in third person; grammatical anomaly
  is the OT's most striking implicit pre-announcement of incarnation.
- 13:7: ami (my associate/fellow citizen) from root amal — YHWH identifies the shepherd as
  his equal/associate (not merely his servant), which is the theological crux for NT application.
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

ZECHARIAH = {
  "8": {
    "1": "<p>Standard messenger formula introducing a new oracle collection. Chapter 8 contains ten distinct oracles each beginning with <em>koh amar YHWH tzvaot</em> (thus says the LORD of Hosts). The repetition of the formula structures the chapter as a deliberate collection of restoration promises, counterbalancing the judgments and calls to repentance in chapters 1-7. The divine name <em>YHWH tzvaot</em> (LORD of Hosts) is particularly dense in Zechariah — used more than 50 times in the book, emphasizing the universal sovereignty of YHWH over all powers as the ground for the restoration promises.</p>",
    "2": "<p><strong>qane qineti leTziyon qinah gedolah vechemath gedolah qaneti lah</strong>: &lsquo;I am burning with jealousy for Zion — great jealousy — and I am stirred with great wrath because of her.&rsquo; <em>Qanna</em>/<em>qinah</em> is the divine jealousy that belongs to the covenant relationship — YHWH&rsquo;s passionate, exclusive commitment to his people (Exod 20:5; 34:14). The term covers both intense love and fierce protectiveness: the jealousy is not petty possessiveness but the burning energy of covenantal fidelity. The doubled construction (great jealousy, great wrath) intensifies the intensity: YHWH is not mildly interested in Zion but passionately committed to her restoration. The wrath (<em>chemah</em>) is directed at those who have oppressed her, not at her herself &mdash; a signal that the restoration era is beginning.</p>",
    "3": "<p><strong>shavti el Tziyon veshachanti betoch Yerushalayim venikra Yerushalayim ir ha-emet vehar YHWH tzvaot har ha-qodesh</strong>: &lsquo;I have returned to Zion and will live in Jerusalem. Jerusalem will be called the City of Truth, and the mountain of the LORD of Hosts will be called the Holy Mountain.&rsquo; The two titles given to the restored Jerusalem define the book&rsquo;s ethical vision: <em>ir ha-emet</em> (city of truth/faithfulness, from <em>emet</em>) and <em>har ha-qodesh</em> (holy mountain). <em>Emet</em> (truth/faithfulness/reliability) becomes the signature virtue of the restored community in this chapter (8:3, 8:16, 8:19). The verb <em>shavti</em> (I have returned) is the same root as the call to the people to &ldquo;return&rdquo; to YHWH (1:3): YHWH&rsquo;s return to Zion is the mirror of the community&rsquo;s return to YHWH.</p>",
    "4": "<p><strong>od yeshvu zeqenim uzeqenot birechovot Yerushalayim</strong>: &lsquo;Old men and old women will once again sit in the streets of Jerusalem, each one leaning on a staff because of great age.&rsquo; The image of the elderly sitting safely in Jerusalem&rsquo;s streets is a picture of civic <em>shalom</em> in its most concrete form — the city is at peace, there is no fear of enemy attack, and the aged are not driven from their homes. Old age was a symbol of YHWH&rsquo;s blessing (Prov 16:31: grey hair is a crown of glory); a city without the elderly was a city stripped of its blessing. The specific detail of the staff (<em>mishenet</em>) because of great age adds verisimilitude: this is not idealized imagery but a picture of actual peaceable life in a well-ordered community.</p>",
    "5": "<p><strong>urechovot ha-ir yimale'u yeladim veyeladot mesachaqim birechovoteyha</strong>: &lsquo;The streets of the city will be full of boys and girls playing in the streets.&rsquo; Children playing safely in city streets is the counterpart to the elderly sitting safely: together they represent the full age-range of the community living in security. The specific verb <em>mesachaqim</em> (playing) is significant — it is the same root used in Genesis 21:9 (Ishmael &ldquo;playing&rdquo; with Isaac), in Judges 16:25 (Samson &ldquo;performing&rdquo; for the Philistines), and in 2 Samuel 6:5 (Israel &ldquo;celebrating&rdquo; before the ark). The picture is of uninhibited joy in public space — the transformation of the city into a place of life and celebration rather than fear and mourning.</p>",
    "6": "<p><strong>ki yippale beeinei she&rsquo;erit ha&rsquo;am hazeh bayamim hahem gam beeinai yippale</strong>: &lsquo;Even if this seems impossible to the remnant of this people in those days, will it also seem impossible to me?&rsquo; The key word is <em>pele</em> (wonderful/miraculous/impossible) — the same root used in Isaiah 9:6 (Wonderful Counselor) and Judges 13:18 (the angel&rsquo;s name is wonderful). YHWH&rsquo;s rhetorical question challenges the community&rsquo;s limited imagination about what is possible: human impossibility is not divine impossibility. The word <em>pele</em> marks the boundary between what humans can accomplish and what YHWH can accomplish — restoration is in the realm of the wonderful, but YHWH specializes in the wonderful.</p>",
    "7": "<p><strong>hineni moshi&rsquo;a et ami me&rsquo;eretz mizrach ume&rsquo;eretz mevo hashemesh</strong>: &lsquo;I will rescue/save my people from the lands of the east and the lands of the west.&rsquo; <em>Moshi&rsquo;a</em> (the participle of <em>yasha</em>, to save/deliver) — the same root as the names Joshua (<em>Yehoshua</em>) and Jesus (<em>Yeshua</em>). YHWH describes himself with the word that will become Christ&rsquo;s name. The universal gathering — from east and west (literally &ldquo;the rising of the sun&rdquo; and &ldquo;the setting of the sun&rdquo;) — encompasses all directions, all exile locations. This universal ingathering pattern (east and west, or all four directions) is the OT template for the NT&rsquo;s eschatological gathering from all nations (Matt 8:11; Rev 7:9).</p>",
    "8": "<p><strong>veheveti otam veshachanu betoch Yerushalayim vehayu li le&rsquo;am va&rsquo;ani ehyeh lahem le&rsquo;elohim be&rsquo;emet uvatzedaqah</strong>: &lsquo;I will bring them home to live in Jerusalem. They will be my people, and I will be their God, in faithfulness and righteousness.&rsquo; The covenant formula (<em>ammi</em> / <em>eloheihem</em> — my people / their God) recurs throughout Scripture from Exodus 6:7 through Jeremiah 31:33 to Revelation 21:3. Here it is qualified with two terms: <em>emet</em> (truth/faithfulness/reliability) and <em>tzedaqah</em> (righteousness/right-relationship). The covenant will be kept with integrity (<em>emet</em>) and in right-relationship (<em>tzedaqah</em>) — both terms pointing to the character of YHWH that grounds the covenant&rsquo;s permanence.</p>",
    "9": "<p><strong>techazaqnah yedeichem</strong>: &lsquo;Let your hands be strong.&rsquo; The call to strengthen weak hands (<em>chazaq yadayim</em>) echoes Ezra 6:22 and the Nehemiah narrative (Neh 2:18: &ldquo;let us rise up and build&rdquo;) — the physical act of rebuilding the temple requires both courage and divine assurance. Isaiah 35:3-4 uses the same idiom in an eschatological register: &ldquo;Strengthen the weak hands, and make firm the feeble knees ... your God will come with vengeance ... he will come and save you.&rdquo; Zechariah is consciously linking the current temple-building community with the broader eschatological promise of divine salvation.</p>",
    "10": "<p><strong>lifnei hayamim hahem</strong>: &lsquo;Before those days.&rsquo; The contrast between the pre-temple period (economic hardship, no safety, enemies on every side) and the current restoration era underscores the theological principle that the presence of YHWH&rsquo;s house in the community transforms its material situation. The economic language — wages, security for travelers, enemies — reflects a comprehensive understanding of <em>shalom</em>: the absence of YHWH&rsquo;s active presence affects every domain of life, not just the religious. The word <em>shelach</em> (to send out/dispatch, used for those going in and out) suggests commercial activity — the restoration includes economic normalcy.</p>",
    "11": "<p><strong>lo chen la&rsquo;am haze kashenim harishoneem</strong>: &lsquo;But from now on I will not deal with the remnant of this people as I did in the past.&rsquo; The emphatic contrast — past dealings vs. future dealings — is YHWH&rsquo;s declaration of a new era. The phrase <em>ka-yamim harishonim</em> (as in the former days) marks the boundary: the era of covenant discipline that scattered and impoverished is over; the era of restoration is beginning. This transition language is the OT&rsquo;s typical structure for the move from judgment to restoration: &ldquo;formerly ... but now&rdquo; (Isa 43:18-19: &ldquo;Remember not the former things ... I am doing a new thing&rdquo;; Jer 31:31-32: &ldquo;not like the covenant I made with their fathers&rdquo;).</p>",
    "12": "<p><strong>ki zera hashalom</strong>: &lsquo;For there will be a sowing of peace / a seed of peace.&rsquo; The phrase <em>zera hashalom</em> (seed/sowing of peace) is a brilliant agricultural metaphor for comprehensive well-being: peace (<em>shalom</em>) is planted like seed that germinates into vine-fruit, ground-produce, and heavenly dew. The vine, ground, and sky producing together is the classic covenantal prosperity (Deut 11:14; Hos 2:21-22), here presented as the fruit of a planted shalom-seed. The comprehensive character of biblical <em>shalom</em> — material, relational, cosmic — is captured in this single agricultural image.</p>",
    "13": "<p><strong>uch&rsquo;asher heyitem qelalah bagoyim beit Yehudah uveit Yisrael ken oshi&rsquo;a etchem viheiyitem berachah</strong>: &lsquo;Just as you, house of Judah and house of Israel, were a curse among the nations, so I will save you, and you will be a blessing.&rsquo; The reversal formula — <em>qelalah</em> (curse) turned to <em>berachah</em> (blessing) — echoes the Abraham promise (Gen 12:2-3: you will be a blessing; whoever curses you I will curse). The exile scattered Israel as a byword and object lesson of divine judgment (Deut 28:37: you will become a horror, a proverb, and a byword); the restoration reverses this: the nations will bless themselves by Israel&rsquo;s name. The &ldquo;house of Judah and house of Israel&rdquo; together (not just the returned southern exiles) points to a reunification of the divided kingdom in the restoration.</p>",
    "14": "<p><strong>kammasher zamam YHWH tzvaot la&rsquo;asot lanu</strong>: &lsquo;Just as I determined to bring disaster upon you when your ancestors provoked me to anger.&rsquo; The word <em>zamam</em> (purposed/determined) is the key term — it is a strong word for deliberate divine intention. YHWH&rsquo;s past determination to punish and current determination to bless are presented as equally firm acts of divine will: just as the judgment was not accidental but purposeful, so the restoration is not tentative but purposed. The symmetry of &ldquo;just as I purposed to harm ... so I have purposed to do good&rdquo; (vv.14-15) is the covenant&rsquo;s two-edged character: the same sovereign will that brought discipline now brings blessing.</p>",
    "15": "<p><strong>shuv zamam ba-yamim ha-eleh la&rsquo;asot tov liYerushalayim uveit Yehudah</strong>: &lsquo;In these days I have determined again to do good to Jerusalem and the house of Judah. Do not be afraid.&rsquo; The double use of <em>zamam</em> (purposed) in vv.14-15 is the theological heart of the passage: YHWH&rsquo;s purposes — whether in judgment or in restoration — are reliable precisely because they are <em>purposed</em>, not reactive. The closing command <em>al tira&rsquo;u</em> (do not be afraid) is the consequence of YHWH&rsquo;s determined purpose: there is no need for fear when the sovereign God has expressed his deliberate intention to do good. This is the OT ground for the NT&rsquo;s &ldquo;the Lord is my helper; I will not fear&rdquo; (Heb 13:6).</p>",
    "16": "<p><strong>devarim asher ta&rsquo;asu dab&rsquo;ru emet ish et re&rsquo;ehu mishpat emet veshalom shiftu bish&rsquo;areichem</strong>: &lsquo;These are the things you must do: Speak the truth to one another. Render honest judgments that lead to peace in your gates.&rsquo; The two commands are <em>emet</em> (truth/faithfulness in speech) and <em>mishpat emet veshalom</em> (judgment of truth-and-peace in the city gates). Both combine <em>emet</em> (truth/reliability) as the core virtue. The gates were the public square where legal disputes were adjudicated (Ruth 4:1-11; Amos 5:10-15); honest gate-justice was the OT&rsquo;s primary institutional accountability mechanism. The pairing of truth and peace (<em>shalom</em>) is the book&rsquo;s ethical formula: shalom grows from emet, not the reverse.</p>",
    "17": "<p><strong>ve&rsquo;ish et ra&rsquo;at re&rsquo;ehu al tachashvu bilvavechem ushvuat sheqer al te&rsquo;ehavu</strong>: &lsquo;Do not plot evil against your neighbor in your heart, and do not love perjury.&rsquo; The two prohibitions address interior disposition (<em>tachashvu bilvavechem</em>, plot in your hearts) and covenant testimony (<em>shvuat sheqer</em>, false oath). The heart-plotting and the perjury together constitute the two forms of relational dishonesty that destroy community from within: private malice and public lying. The phrase <em>ki et kulam eleh sane&rsquo;ti</em> (for all these things I hate, declares the LORD) uses <em>sane</em> (hate) — the same strong term of divine aversion used in the Proverbs list of what YHWH hates (Prov 6:16-19), where both &ldquo;a false witness who breathes out lies&rdquo; and &ldquo;one who sows discord among brothers&rdquo; appear.</p>",
    "18": "<p>Transitional oracle formula. The word of the LORD coming &ldquo;to me&rdquo; (<em>elai</em>) is the standard prophetic reception formula, signaling a new oracle unit within the larger collection. Chapter 8 shifts here from ethical commands (vv.16-17) to eschatological promises (vv.19-23) — the ethical demands are grounded in and directed toward the eschatological vision of universal peace that follows.</p>",
    "19": "<p><strong>tzom harevi&rsquo;i vetzom hachamishi vetzom hashvi&rsquo;i vetzom ha&rsquo;asiri yihyeh leveit Yehudah lesason ulesimchah ulemo&rsquo;adim tovim</strong>: &lsquo;The fasts of the fourth, fifth, seventh, and tenth months will become occasions of joy and gladness and cheerful festivals.&rsquo; The four fasts commemorated specific catastrophes of the Babylonian period (fourth month: Jerusalem breached; fifth: temple burned; seventh: Gedaliah murdered; tenth: siege begun). Their transformation into feasts is the comprehensive eschatological reversal of the exile&rsquo;s grief: the specific dates of historical disaster become the dates of eschatological celebration. The closing clause — <em>veha-emet veha-shalom ehavu</em> (love truth and peace) — is the ethical foundation for this transformation: the fasts become feasts not automatically but through a community characterized by <em>emet</em> and <em>shalom</em>.</p>",
    "20": "<p><strong>od asher yavo&rsquo;u ammim veyoshevei arim rabbot</strong>: &lsquo;Peoples will yet come — inhabitants of many cities.&rsquo; The eschatological pilgrimage of the nations to Jerusalem is the OT&rsquo;s vision of universal worship that runs from Isaiah 2:2-4 (all nations streaming to YHWH&rsquo;s mountain) through Micah 4:1-3 to this passage. The phrase <em>od asher yavo&rsquo;u</em> (peoples will yet come) introduces the coming universal movement as still future but certain: the &ldquo;yet&rdquo; (<em>od</em>) acknowledges the current partial state of affairs while affirming its ultimate completion.</p>",
    "21": "<p><strong>nilchah venelchah el pnei YHWH ulevaqesh et YHWH tzvaot</strong>: &lsquo;Let us go immediately to seek the LORD&rsquo;s favor and to seek the LORD of Hosts.&rsquo; The speech among the nations — city inviting city to make pilgrimage — represents the spontaneous spread of the desire to seek YHWH among the Gentiles. The verb <em>chalah pnei</em> (seek the LORD&rsquo;s favor, literally &ldquo;soften/entreat the face of&rdquo;) is a technical term for seeking divine favor, often in crisis (Ps 119:58; Dan 9:13). The urgency of the invitation — <em>nilchah</em> (let us go quickly) — expresses the eschatological eagerness that characterizes the nations&rsquo; turning to YHWH.</p>",
    "22": "<p><strong>veba&rsquo;u ammim rabbim vegoyim atzumim livaqesh et YHWH tzvaot biYerushalayim ulechalot et pnei YHWH</strong>: &lsquo;Many peoples and powerful nations will come to seek the LORD of Hosts in Jerusalem and to seek the LORD&rsquo;s favor.&rsquo; The escalating scope — many peoples and powerful/numerous nations — makes the pilgrimage universal in reach. The double verb pair (<em>livaqesh</em> to seek + <em>lechalot</em> to seek favor) intensifies the earnestness of the nations&rsquo; approach. This verse is the OT background for Isaiah 2:3 (&ldquo;many peoples shall come and say: Come, let us go up to the mountain of the LORD&rdquo;) and for the NT&rsquo;s vision of the church as the gathering-point for all nations (John 12:32: &ldquo;when I am lifted up, I will draw all people to myself&rdquo;).</p>",
    "23": "<p><strong>koh amar YHWH tzvaot bayamim hahem asher yachaziqu asarah anashim mikol leshonot hagoyim vehecheziku bichnaph ish Yehudi lemor nelchah imachem ki shama&rsquo;nu Elohim imachem</strong>: &lsquo;In those days ten men from every nation and language will take hold of the garment of a Jew, saying, Let us go with you, for we have heard that God is with you.&rsquo; The image of ten men from every nation grasping the hem of a Jewish man&rsquo;s garment is the OT&rsquo;s most vivid picture of Gentile inclusion through Israel&rsquo;s witness. Ten is a symbolic number of completeness (a minyan, the quorum for synagogue prayer); &ldquo;from every nation and language&rdquo; is universal; &ldquo;God is with you&rdquo; (<em>Elohim imachem</em>) is the Immanuel formula (Isa 7:14: God-with-us, Emmanuel) applied to the restored community. The garment-grasping (<em>bichnaph ish</em>, by the hem of a man) is an act of supplication — the nations approaching Israel not with hostility but with petition.</p>"
  },
  "9": {
    "1": "<p><strong>massa devar YHWH be&rsquo;eretz Chadrach veDamaseq menuchato</strong>: &lsquo;An oracle — the word of the LORD against the land of Hadrach; Damascus is where it comes to rest.&rsquo; <em>Massa</em> (oracle/burden) is the technical term for a prophetic oracle, often against foreign nations (used in Isa 13-23; Nah 1:1). The specific geography — Hadrach (Hatarikka in Assyrian records, north of Damascus), Damascus, Hamath, Tyre, Sidon — traces the Syro-Phoenician coastal region from north to south, then turns to Philistia in vv.5-7. This geographical progression from north to south mirrors the approach of Alexander the Great&rsquo;s campaign (332 BCE), leading many scholars to see it as a prophecy of Alexander&rsquo;s conquests — a reading that would place the oracle&rsquo;s &ldquo;fulfillment&rdquo; in 332 BCE before the ultimate fulfillment in Christ.</p>",
    "2": "<p><strong>vegam Chamath tigbal bah Tzor veTzidon ki chakemah me&rsquo;od</strong>: &lsquo;And also Hamath, which borders Damascus, Tyre and Sidon, though they are very clever.&rsquo; The clause <em>ki chakemah me&rsquo;od</em> (though they are very clever/wise) is ironic: the legendary wisdom and commercial acumen of Tyre and Sidon (Ezek 28:3-5 develops this at length) cannot prevent YHWH&rsquo;s judgment. The same ironic treatment of &ldquo;wisdom&rdquo; (human cleverness that cannot outmaneuver divine judgment) appears in 1 Corinthians 1:20-25: &ldquo;Where is the one who is wise?...God has made foolish the wisdom of the world.&rdquo;</p>",
    "3": "<p><strong>vativen Tzor matsor lah vatatzbar kesef ke&rsquo;afar vecharutz kimid ulechot</strong>: &lsquo;Tyre has built herself a fortress and amassed silver like dust and gold like the mud of the streets.&rsquo; The accumulation language (<em>vatatzbar</em>, she has heaped up) and the extreme comparisons (silver like dust, gold like mud) describe the hyperbolic wealth of Tyre, the Mediterranean&rsquo;s greatest trading port. The contrast between the extraordinary wealth of accumulated trade (<em>kesef ke&rsquo;afar</em>, silver like dust) and the dismissive terms in which it is compared (dust, mud of streets) undercuts the apparent permanence of commercial wealth. Ezekiel 28 develops the Tyre oracle into the most extensive biblical meditation on pride born of commercial success.</p>",
    "4": "<p><strong>hineh Adonay yoreshennah vehikah bayam cheilah vehi ba&rsquo;esh te&rsquo;akel</strong>: &lsquo;But look — the Lord will dispossess her and hurl her wealth into the sea, and she will be consumed by fire.&rsquo; The sudden divine reversal — all that accumulated wealth hurled into the sea from which it came — is YHWH&rsquo;s judgment turning Tyre&rsquo;s commercial identity against her. The sea that made Tyre wealthy becomes the receptacle of her destruction. This pattern (a power&rsquo;s defining feature becoming the instrument of its judgment) is consistent throughout the Prophets: the sea-people destroyed by the sea; the shepherd-king struck; the temple destroyed.</p>",
    "5": "<p><strong>tir&rsquo;eh Ashqelon vetira Gaza tigel me&rsquo;od ve&rsquo;Eqron ki hovish miqvavetah</strong>: &lsquo;Ashkelon will see it and be terrified; Gaza too, writhing in anguish; and Ekron, for its hope has withered.&rsquo; The three Philistine cities&rsquo; reaction to Tyre&rsquo;s fall — fear, anguish, withered hope — is the chain reaction of psychological collapse when a great regional power falls: those who depended on its trade networks and military protection suddenly find themselves exposed. <em>Miqveh</em> (hope, literally that which is expected/awaited) withering for Ekron means its anticipated future of prosperity evaporates when the patron city falls.</p>",
    "6": "<p><strong>veyashav mamzer be&rsquo;Ashdod vehichrati ge&rsquo;on Pelishtim</strong>: &lsquo;A mixed people will settle in Ashdod, and I will cut off Philistia&rsquo;s pride.&rsquo; <em>Mamzer</em> (literally &ldquo;illegitimate/mixed&rdquo; — a person of uncertain or mixed parentage) settling in Ashdod signifies the disruption of Philistia&rsquo;s ethnic and cultural cohesion — the city will be populated by displaced, mixed populations rather than the proud Philistine aristocracy. <em>Ge&rsquo;on</em> (pride, majesty, arrogance) is cut off — the same term used of Israel&rsquo;s pride (Amos 6:8; Hos 5:5) and of the pride that YHWH destroys throughout the Prophets. Pride is consistently the divine target in judgments on both nations and individuals.</p>",
    "7": "<p><strong>vehesiroti demav mipiv veshuqtzav mibeyn shenav venish&rsquo;ar gam hu leEloheinu</strong>: &lsquo;I will strip the blood from its mouth and the forbidden offerings from between its teeth. Even they will belong to our God.&rsquo; The remarkable inclusion at the end of the verse — the formerly pagan Philistines belonging to YHWH — is the eschatological surprise of the oracle. Blood in the mouth and forbidden food between the teeth represent Philistia&rsquo;s cultic impurity; their removal is the purification that enables inclusion. The comparison to a &ldquo;clan leader in Judah&rdquo; and Ekron becoming &ldquo;like the Jebusites&rdquo; (who were absorbed into Israel after David captured Jerusalem) shows that Gentile incorporation into the covenant community is the oracle&rsquo;s endpoint.</p>",
    "8": "<p><strong>vechaniti leveti mitzava me&rsquo;over ume&rsquo;shav velo ya&rsquo;avor aleihem od nages</strong>: &lsquo;I will take up position around my house as a garrison, so that no army marches through it again. No oppressor will march over them, for now my eyes watch over them.&rsquo; YHWH as garrison around his house — the divine protection of the restored community through YHWH himself acting as military guard. The promise <em>ki atta ra&rsquo;iti be&rsquo;einay</em> (for now I watch with my eyes) is the assurance of divine surveillance and care replacing the vulnerability that made conquest possible. This verse is structurally the pivot between the judgment oracles against the nations (vv.1-7) and the messianic announcement (vv.9-10) — YHWH secures his house so the king can come.</p>",
    "9": "<p><strong>gili me&rsquo;od bat Tzion hari&rsquo;i bat Yerushalayim hineh malkeich yavo lach tzaddiq venoshia hu ani verocheiv al chamor ve&rsquo;al &lsquo;ayir ben atenot</strong>: &lsquo;Rejoice greatly, Daughter Zion! Shout aloud, Daughter Jerusalem! See — your king is coming to you, righteous and having-salvation, humble and riding on a donkey, on a colt, the foal of a she-donkey.&rsquo; The two Hebrew terms require careful analysis: (1) <em>tzaddiq</em> (righteous): the king is intrinsically righteous — this is a character attribute, not merely a status. (2) <em>venoshia</em>: the Niphal form of <em>yasha</em> (to save), meaning &ldquo;being-saved&rdquo; or &ldquo;having-salvation&rdquo; — this is the rarer reading. The king does not save himself; he is saved by YHWH, or he is one who has/carries salvation from YHWH. The contrast between the war-horse (<em>sus</em>) and the donkey (<em>chamor</em>) + colt (<em>&lsquo;ayir</em> + <em>ben atenot</em>) signals the nature of his kingdom: a king on a war-horse signals conquest; a king on a donkey signals peace and accessibility. <em>Ani</em> (humble/poor/afflicted) is the same term used in Psalm 22:24 of the one whose cry YHWH heard — the paradigmatic sufferer-and-redeemed.</p>",
    "10": "<p><strong>vehikrati rechev me&rsquo;Efraim vesus miYerushalayim venikretah qeshet milchamah vedibbar shalom lagoyim umoshelo miyam ad yam uminarahot ad afsei aretz</strong>: &lsquo;He will cut off the chariot from Ephraim and the war horse from Jerusalem; the battle bow will be cut off. He will proclaim peace to the nations. His dominion will be from sea to sea and from the River to the ends of the earth.&rsquo; The disarmament by the messianic king — he removes the chariot, horse, and bow from the covenant community — signals the arrival of the eschatological peace age. <em>Vediber shalom lagoyim</em> (he will speak/proclaim peace to the nations): the king&rsquo;s speech itself establishes peace, not merely announces it. The universal dominion formula — <em>miyam ad yam</em> (from sea to sea) + <em>minarahot ad afsei aretz</em> (from the River to the ends of the earth) — echoes Psalm 72:8, the royal psalm of ideal Davidic reign now applied to the messianic king whose kingdom encompasses all.</p>",
    "11": "<p><strong>gam at bedam beritayich shilachti asirayich mibbor ein maim bo</strong>: &lsquo;As for you — because of the blood of my covenant with you — I will free your prisoners from the waterless pit.&rsquo; <em>Dam beritayich</em> (blood of my covenant with you) — the blood of the Sinai covenant (Exod 24:8: &ldquo;this is the blood of the covenant that YHWH has made with you&rdquo;) is the basis for the liberation of prisoners. The <em>bor ein maim</em> (waterless pit) echoes Joseph&rsquo;s pit (Gen 37:24: the pit had no water in it) and Jeremiah&rsquo;s cistern (Jer 38:6). The contrast between &ldquo;waterless pit&rdquo; and &ldquo;fortress of hope&rdquo; (v.12) is the liberation movement from imprisonment to security. Jesus quotes this verse&rsquo;s liberation theme (Luke 4:18: &ldquo;to proclaim liberty to the captives&rdquo;) and the &ldquo;blood of the covenant&rdquo; becomes the central phrase of the Last Supper (Matt 26:28: &ldquo;this is my blood of the covenant&rdquo;).</p>",
    "12": "<p><strong>shuvah levitzaron asirei hatiqvah gam hayom maggid mishneh asiv lach</strong>: &lsquo;Return to the stronghold, you prisoners who still have hope; today I declare that I will restore double to you.&rsquo; <em>Bitzaron</em> (stronghold/fortress) — the secure place of refuge that YHWH promises to the hopeful prisoners. <em>Asirei hatiqvah</em> (prisoners of hope) is a beautiful paradox: those who are imprisoned yet have hope (in YHWH&rsquo;s promise). The double restoration (<em>mishneh</em>) echoes the Job pattern (Job 42:10: YHWH restored Job&rsquo;s fortunes double) and the Isaiah promise (Isa 40:2: Jerusalem has received double for all her sins; 61:7: you will receive a double portion instead of shame). The return to the stronghold — from waterless pit to fortress — is the rescue movement accomplished by the blood-of-covenant liberation.</p>",
    "13": "<p><strong>ki darakhti li Yehudah qeshet milleti Efraim ve&rsquo;orerti vanayich Tziyon al vanayich Yavan</strong>: &lsquo;For I have bent Judah like a bow; I have made Ephraim its arrow. I will rouse your sons, Zion, against the sons of Greece.&rsquo; YHWH himself as the one who bends the bow and nocks the arrow — using Judah and Ephraim as weapons — is the divine-warrior imagery at its most concrete. The specific mention of <em>Yavan</em> (Greece/Javan) is one of the only explicit references to the Greek world in the Hebrew prophets, and may point to the Maccabean period or be deliberately eschatological. The combat between the sons of Zion and the sons of Greece is a historical specificity that becomes the broader conflict between the covenant community and the Hellenizing pressures that climaxed in Antiochus Epiphanes&rsquo; program.</p>",
    "14": "<p><strong>va&rsquo;Adonay aleyhem yera&rsquo;eh veyatza chakatzetz baraqo uAdonay Elohim bashofer yitqa vealach bese&rsquo;arot teman</strong>: &lsquo;The LORD will appear over them; his arrow will flash like lightning. The Lord GOD will sound the trumpet and march in the storms of the south.&rsquo; The theophanic imagery of divine appearance — lightning-arrow, trumpet-blast, storm-march — is drawn from the Sinai traditions (Exod 19:16-19: thunder, lightning, thick cloud, loud trumpet) and the divine-warrior psalms (Ps 18:14: he sent out his arrows and scattered them; he flashed forth lightnings and routed them). The combination of visual (lightning), auditory (trumpet), and physical (storm from the south) elements creates a comprehensive theophanic announcement of divine intervention on behalf of his people.</p>",
    "15": "<p><strong>YHWH tzvaot yagen aleihem ve&rsquo;achelu vekaveshu even qela&rsquo; veshatu hamah kimayim mizraq</strong>: &lsquo;The LORD of Hosts will shield them. They will devour and trample the sling stones; they will drink and shout as with wine.&rsquo; The vivid battle imagery — devouring sling stones, drinking and shouting — is the OT&rsquo;s hyperbolic celebration of victorious warriors who are unstoppable because YHWH shields them. The verb <em>yagen</em> (shield, protect, cover) is the word for YHWH as shield throughout the psalms (Ps 18:30: YHWH is a shield to those who take refuge in him). The battle hymn quality of this verse points forward to the eschatological warfare motifs of Revelation 19.</p>",
    "16": "<p><strong>vehoshi&rsquo;am YHWH Eloheihem bayom hahu ketzon ammo ki avnei nezer mitnoseshot al admatho</strong>: &lsquo;On that day the LORD their God will save them as his people&rsquo;s flock. They will gleam like gems in a crown over his land.&rsquo; The pastoral/royal double image — saved as a flock (<em>tzon ammo</em>, sheep of his people) but gleaming like gems in a crown (<em>avnei nezer</em>) — combines the shepherd metaphor with the coronation image. The people of YHWH are both sheep (needing a shepherd) and jewels (precious to the king). The word <em>nezer</em> (crown/diadem) is used for the high priest&rsquo;s golden crown (Exod 29:6) and the royal diadem: the restored people are simultaneously priestly and royal — the description of the eschatological community as &ldquo;a kingdom of priests&rdquo; (Exod 19:6; 1 Pet 2:9) applied here.</p>",
    "17": "<p><strong>ki mah tuvah umah yofyah dagan bachurim vethirosh yenovev betulot</strong>: &lsquo;How great is his goodness, how great is his beauty! Grain will strengthen the young men, and new wine will cheer the young women.&rsquo; The exclamation <em>mah tuvah umah yofyah</em> (how great is his goodness, how great is his beauty!) is YHWH&rsquo;s goodness and beauty celebrated — <em>tuv</em> (goodness, bounty) and <em>yofi</em> (beauty, splendor). The agricultural prosperity that follows — grain for young men, new wine for young women — is the material embodiment of divine goodness. The pairing of <em>dagan</em> (grain) and <em>tirosh</em> (new wine) is the standard covenantal blessing pair (Deut 7:13; 11:14; Hos 2:8), here representing the full restoration of covenant prosperity.</p>"
  },
  "10": {
    "1": "<p><strong>she&rsquo;alu meYHWH matar be&rsquo;et matar malqosh YHWH oseh chazizim umtar geshem yiten lahem le&rsquo;ish esev basadeh</strong>: &lsquo;Ask rain from the LORD in the season of the spring rain. The LORD is the one who makes the storm clouds; he will give them showers of rain and grass in the fields for everyone.&rsquo; <em>Malkosh</em> (spring rain / latter rain) is the crucial rain that falls in March-April, completing the grain&rsquo;s growth before harvest. The call to ask YHWH specifically for rain (rather than consulting the teraphim of v.2) frames vv.1-2 as a contrast: YHWH gives the actual rain; idols give only worthless speech. The theological principle: the one who controls the rain controls the food supply, and therefore all political and economic power ultimately derives from YHWH — the point Elijah made against Baal on Carmel (1 Kgs 17-18).</p>",
    "2": "<p><strong>ki hateraphim dibru aven vehaqqosemim chazu shaqer vachalomot hashav yedaberu hevel yenachamun</strong>: &lsquo;For the household idols speak worthlessness, and the diviners see false visions; they tell lying dreams and give empty comfort.&rsquo; The <em>teraphim</em> (household gods, small figurines used for divination and protection) are contrasted with YHWH who gives real rain and real help. <em>Aven</em> (worthlessness/trouble), <em>shaqer</em> (falsehood), <em>shav</em> (emptiness/vanity), <em>hevel</em> (breath/vapor — the Ecclesiastes word for meaninglessness) — the four terms are a lexicon of futility. The idols&rsquo; comfort (<em>yenachamun</em>) is empty because they cannot control the physical world they claim to govern; only YHWH who makes the rain can offer real consolation.</p>",
    "3": "<p><strong>al haro&rsquo;im chara appi ve&rsquo;al ha&rsquo;attudim eqod ki paqad YHWH tzvaot et edro et beit Yehudah</strong>: &lsquo;My anger burns against the shepherds, and I will punish the leaders; for the LORD of Hosts tends his flock, the house of Judah, and will make them like his majestic horse in battle.&rsquo; <em>Ro&rsquo;im</em> (shepherds) and <em>attudim</em> (he-goats, leaders/chief men) are parallel terms for the ruling class — using the pastoral/flock metaphor for political leadership (common in the ancient Near East). YHWH&rsquo;s punishment of the negligent shepherds leads directly to his own shepherding of the flock (Ezek 34 develops this extensively). The transformation of the flock from sheep to a war-horse (<em>sus hod</em>, majestic/stately battle horse) is the reversal of helplessness into strength through YHWH&rsquo;s care.</p>",
    "4": "<p><strong>mimenu pinnah mimenu yated mimenu qeshet milchamah mimenu yetze kol noges yachdav</strong>: &lsquo;From Judah will come the cornerstone, from him the tent peg, from him the battle bow, from him every ruler — all of them together.&rsquo; Three structural images — <em>pinnah</em> (cornerstone, the structural foundation stone), <em>yated</em> (tent peg, the anchor pin that holds the structure), and <em>qeshet milchamah</em> (battle bow, the offensive military weapon) — describe the comprehensive messianic leadership arising from Judah. The cornerstone is the key Christological term: Isaiah 28:16 (I lay in Zion a cornerstone, a tested stone, a precious cornerstone); Psalm 118:22 (the stone the builders rejected has become the cornerstone); and Jesus&rsquo;s own citation of Psalm 118:22 (Matt 21:42) plus Peter (1 Pet 2:6-7) and Paul (Eph 2:20) apply the cornerstone directly to Christ.</p>",
    "5": "<p><strong>vehayu kegibborim boshim barei chutzot bamilchamah</strong>: &lsquo;Together they will be like mighty warriors in battle, trampling their enemies in the street mud. They will fight because the LORD is with them.&rsquo; The revival of the Judean warriors — transformed from scattered sheep to mighty warriors — is YHWH&rsquo;s military empowerment of his people. The critical phrase is <em>ki YHWH imam</em> (for the LORD is with them) — the Immanuel principle as the ground for military effectiveness. The battle capability does not originate in the people&rsquo;s own strength but in the divine presence: &ldquo;not by might, nor by power, but by my Spirit&rdquo; (Zech 4:6) is the theological framework governing all the battle imagery.</p>",
    "6": "<p><strong>vegibbarti et beit Yehudah ve&rsquo;et beit Yosef oshi&rsquo;a veoshivotim ki richamtim</strong>: &lsquo;I will strengthen the house of Judah and save the house of Joseph. I will bring them back, for I have compassion on them.&rsquo; <em>Richamtim</em> (I have compassion on them) — from <em>rachamim</em> (compassion, womb-love, the deepest maternal/covenant love). The reunification of Judah and Joseph (= Ephraim = the northern kingdom) is the eschatological reversal of the kingdom division (931 BCE) and the Assyrian deportation (722 BCE): the full twelve-tribe Israel restored through divine compassion. The promise <em>ki anochi YHWH Eloheihem ve&rsquo;e&rsquo;eneh otam</em> (for I am YHWH their God and I will answer them) is the covenant self-identification as the ground of the promise.</p>",
    "7": "<p><strong>vehayu chigibor Efraim vesamas libam kayayin uveneihem yiru visamechu yagel libam baYHWH</strong>: &lsquo;Ephraim will be like a mighty warrior, and their hearts will rejoice as with wine. Their children will see it and be glad; their hearts will rejoice in the LORD.&rsquo; The joy of restoration is expressed through the wine-gladness metaphor (<em>yism&rsquo;as libam kayayin</em>, their hearts will rejoice as with wine) — the exhilarating joy of warriors victorious in YHWH&rsquo;s strength. The intergenerational dimension — children seeing and rejoicing — emphasizes that the restoration is comprehensive and lasting, affecting future generations, not just the present survivors. The joy is specifically in YHWH (<em>yagel libam baYHWH</em>), not in the victory itself.</p>",
    "8": "<p><strong>eshrqah lahem ve&rsquo;eqobbetzem ki pedaytim verabu kamah ravu</strong>: &lsquo;I will signal for them and gather them, for I have redeemed them; they will be as numerous as before.&rsquo; <em>Eshrqah</em> (I will whistle/signal) — YHWH calling his people like a shepherd whistling for his sheep or a beekeeper signaling a swarm. Isaiah 5:26 uses a different signal metaphor (YHWH raising a flag for distant nations), but the signaling of scattered peoples to return is a consistent divine-shepherd action. <em>Pedaytim</em> (I have redeemed them) — the redemption verb <em>pada</em> (used for the firstborn redeemed from death, Exod 13:13; for Israel redeemed from Egypt, Deut 7:8) is here used proleptically: the gathering is the enactment of a redemption already accomplished in divine purpose.</p>",
    "9": "<p><strong>va&rsquo;ezraem ba&rsquo;ammim uvemerchaqqim yizkeruni veyachyu et beneihem veshabu</strong>: &lsquo;Though I scattered them among the nations, they will remember me even in distant countries; they will survive with their children and return.&rsquo; The divine scattering (<em>ezraem ba&rsquo;ammim</em>) that is the instrument of punishment becomes the context of memory (<em>yizkeruni</em>, they will remember me). The dispersion that seemed like abandonment becomes the occasion for the diaspora&rsquo;s return to YHWH — the exile&rsquo;s spiritual purpose is the deepening of YHWH-remembrance at a distance. This is the OT&rsquo;s explanation for why diaspora experience can strengthen rather than destroy faith: the absence from the land intensifies the longing for the covenantal God.</p>",
    "10": "<p><strong>vahashivotim me&rsquo;eretz Mitzraim ume&rsquo;Ashur aqabbetzem ve&rsquo;el eretz Gil&rsquo;ad uLevanon aviam velo yimmatze lahem</strong>: &lsquo;I will bring them back from Egypt and gather them from Assyria. I will settle them in Gilead and Lebanon until there is no room for them.&rsquo; The pairing of Egypt and Assyria as the two poles of exile represents the totality of the scattered diaspora — the Egyptian and Mesopotamian ends of the ancient Near East. Gilead (Transjordan) and Lebanon (the northern territory) are the marginal lands that will receive the overflow population of the restored community. The phrase <em>velo yimmatze lahem</em> (until there is no room/found for them) implies such abundance of returnees that even the border regions fill up — a reversal of the emptied land of exile.</p>",
    "11": "<p><strong>ve&rsquo;avar vayam tzarah vehikah vayam gallim veyavesha kol metzolelot ye&rsquo;or</strong>: &lsquo;He will pass through the sea of distress and strike down the waves; all the depths of the Nile will dry up.&rsquo; The new Exodus imagery — passing through the sea, striking down waves, drying up the Nile — applies the Exodus pattern (the Red Sea crossing) to the eschatological ingathering. The Assyrian and Egyptian powers are symbolized by their great rivers: Assyria by the Euphrates, Egypt by the Nile. YHWH drying up the Nile depths reverses the plagues (Exod 7-12) in a new register: instead of turning water to blood as judgment, he dries the rivers to create a passage for returning exiles (Isa 11:15-16 develops the same new-Exodus motif).</p>",
    "12": "<p><strong>vegibbarti otam baYHWH uvshemo yithalaku ne&rsquo;um YHWH</strong>: &lsquo;I will strengthen them in the LORD, and they will walk in his name, declares the LORD.&rsquo; The closing verse of the chapter combines two key covenant concepts: <em>ugebibartim baYHWH</em> (I will strengthen them in the LORD — the covenant relationship as the source of strength, not their own power) and <em>uvshemo yithalaku</em> (they will walk in his name — the covenantal lifestyle of <em>halakha</em>, walking according to YHWH&rsquo;s revealed character). The &ldquo;name&rdquo; (<em>shem</em>) of YHWH is not merely a label but the full revelation of his character and power; to walk &ldquo;in the name&rdquo; is to live in alignment with who YHWH is. The NT equivalent: &ldquo;whatever you do in word or deed, do everything in the name of the Lord Jesus&rdquo; (Col 3:17).</p>"
  },
  "11": {
    "1": "<p><strong>petach Levanon daltoteycha ve&rsquo;tochal esh be&rsquo;arazeycha</strong>: &lsquo;Open your doors, Lebanon, so that fire may devour your cedars!&rsquo; The oracle against Lebanon&rsquo;s forests is a poetic announcement of imminent destruction: the great cedar forests of Lebanon (a symbol of prestige and power throughout the ancient Near East — Solomon used Lebanese cedar for the temple, 1 Kgs 5) will be consumed by fire. The ironic command to open the doors (letting the destroying fire in) is the prophetic rhetoric of helplessness before divine judgment. The pastoral images of destroyed trees (cedars, cypresses, oaks of Bashan) in vv.1-3 frame the allegory of the failed shepherd that follows.</p>",
    "2": "<p><strong>heilil berosh ki nafal erez asher adarim shudadu heililu allonei Bashan ki yarad ya&rsquo;ar habatzur</strong>: &lsquo;Wail, cypress tree, for the cedar has fallen; the majestic trees are destroyed! Wail, oaks of Bashan, for the dense forest has fallen.&rsquo; The lamentation of trees over other trees is the prosopopoeia (personification) that characterizes prophetic poetry: the natural world mourns the destruction of the great ones (cedars = imperial powers; oaks of Bashan = regional powers). The descending order — Lebanon cedar, cypress, Bashan oak — traces the collapse of power from the greatest to the lesser. This imagery is the background for Revelation&rsquo;s destruction of &ldquo;every tree&rdquo; (Rev 8:7) as eschatological judgment.</p>",
    "3": "<p><strong>qol yelalat haro&rsquo;im ki shudad addaretam qol sha&rsquo;agat keppirim ki shudad ge&rsquo;on haYarden</strong>: &lsquo;Listen to the cry of the shepherds — their splendor is destroyed! Listen to the roar of the young lions — the pride of the Jordan is ruined.&rsquo; The shepherds&rsquo; cry and the lions&rsquo; roar together frame the coming allegory: the rulers (shepherds) and the powerful (young lions) of the region will all be destroyed. The pride of the Jordan (<em>ge&rsquo;on haYarden</em>) is the Jordan&rsquo;s thicket — the dense vegetation along the riverbank where lions lived (Jer 49:19; 50:44) — representing natural power and abundance now stripped away. The transition from forest imagery to the shepherd allegory (vv.4ff.) is smooth: the forest is the context, the shepherds are the actors.</p>",
    "4": "<p><strong>koh amar YHWH Elohai re&rsquo;eh et tzon ha&rsquo;haregah</strong>: &lsquo;This is what the LORD my God says: Shepherd the flock marked for slaughter.&rsquo; <em>Tzon ha&rsquo;haregah</em> (flock of slaughter/flock destined for killing) — the flock is not merely at risk but has been designated for destruction by its own owners. This is the shocking premise of the allegory: the people are being treated as livestock for slaughter rather than as a flock to be protected. The prophet is commanded to act as a good shepherd for this abandoned, exploited flock — an enacted metaphor for YHWH&rsquo;s own faithful shepherding of his people despite their leaders&rsquo; exploitation.</p>",
    "5": "<p><strong>asher qoneihen yehargum velo ye&rsquo;shamu umochreihem yomru baruch YHWH va&rsquo;ashar</strong>: &lsquo;Their buyers slaughter them without guilt. Those who sell them say, &ldquo;Praise the LORD — I have become rich!&rdquo; And their shepherds have no compassion on them.&rsquo; The buyers and sellers of the flock-people (the exploiting leadership) are portrayed in stark moral terms: the buyers kill without guilt (<em>lo ye&rsquo;shamu</em>, no guilt felt); the sellers even invoke YHWH&rsquo;s name to celebrate their profit. The use of <em>baruch YHWH</em> (blessed/praised be YHWH) in the context of exploitation is the OT&rsquo;s most pointed example of religiosity weaponized for self-enrichment — the exact target of Amos 8:4-6 and Jesus&rsquo;s condemnation of those who &ldquo;devour widows&rsquo; houses and for a pretense make long prayers&rdquo; (Mark 12:40).</p>",
    "6": "<p><strong>ki lo achus od al yoshvei ha&rsquo;aretz ne&rsquo;um YHWH vehineni mematzzi et ha&rsquo;adam</strong>: &lsquo;For I will no longer spare the inhabitants of the land, declares the LORD. I am about to hand each person over to his neighbor and to his king.&rsquo; <em>Lo achus</em> (I will no longer spare/have compassion) — the withdrawal of divine protection, allowing the natural consequences of human exploitation and political chaos to play out. The phrase <em>mematzzi et ha&rsquo;adam ish beyad re&rsquo;ehu uveyad malko</em> (handing each person over to his neighbor and his king) describes social and political breakdown: when YHWH withdraws his protection, the community fragments into mutual exploitation. This is the darkest form of divine judgment — not active punishment but the withdrawal of the restraining grace that kept human evil in check.</p>",
    "7": "<p><strong>ve&rsquo;er&rsquo;eh et tzon ha&rsquo;haregah lachen ani aniyei hatzon va&rsquo;eqqach li shnei maqelot le&rsquo;achad qarati No&rsquo;am uvele&rsquo;achad qarati Chovlim va&rsquo;er&rsquo;eh et hatzon</strong>: &lsquo;So I shepherded the flock marked for slaughter — the flock the dealers exploited. I took two staffs, calling one Favor and the other Union, and I shepherded the flock.&rsquo; The two staffs name the two dimensions of YHWH&rsquo;s covenant relationship: <em>No&rsquo;am</em> (Favor/Grace/Beauty/Pleasant) represents YHWH&rsquo;s gracious covenantal relationship with his people; <em>Chovlim</em> (Union/Binders) represents the internal unity between Judah and Israel. Both are eventually broken in the allegory (vv.10, 14), signifying the ending of both dimensions — divine favor and national unity.</p>",
    "8": "<p><strong>va&rsquo;achid shlosha haro&rsquo;im biyerach echad vatiqtzar nafshi bahem vegam nafshtam ba&rsquo;ala bi</strong>: &lsquo;In one month I did away with three shepherds. But I grew impatient with them, and they loathed me in return.&rsquo; The three shepherds dismissed in one month are among the most debated references in Zechariah — no consensus identification has emerged. Possibilities include three leadership offices (prophet, priest, king), three Hasmonean rulers, three classes of foreign rulers, or a generic reference to the rapid succession of failed leaders. The mutual loathing (<em>vatiqtzar nafshi bahem ... nafshtam ba&rsquo;ala bi</em>) — the prophet impatient with the shepherds, the shepherds loathing the prophet — reflects the fundamental breakdown of leadership accountability that characterizes the period.</p>",
    "9": "<p><strong>va&rsquo;omar lo er&rsquo;eh etchem hamemet yamat vehanichcadet tikavet vehannish&rsquo;arot to&rsquo;chalnah isha et besar re&rsquo;utah</strong>: &lsquo;So I said, &ldquo;I will no longer shepherd you. What is dying, let it die; what is to be destroyed, let it be destroyed; and those who are left will devour each other.&rdquo;&rsquo; The withdrawal of the shepherd — the declaration that no more care will be given — is the most severe form of divine judgment in the shepherd-metaphor. The three-part fate (dying die, destroyed destroyed, survivors eat each other) is the escalating horror of complete social breakdown. This is the judgment that falls when the divine shepherd withdraws, and it functions as the enacted prophecy of the siege of Jerusalem in 70 CE, where Josephus reports the internal conflicts of the besieged city.</p>",
    "10": "<p><strong>va&rsquo;eqqach et maqeli et No&rsquo;am va&rsquo;egda oto lehfer et beriti asher karati et kol ha&rsquo;ammim</strong>: &lsquo;Then I took my staff called Favor and broke it, canceling the covenant I had made with all the peoples.&rsquo; The breaking of the Favor staff cancels the covenant with &ldquo;all the peoples&rdquo; — interpreted as YHWH&rsquo;s restraint of the nations from destroying Israel (a protective covenant). When this protective covenant is revoked, the nations are free to exercise their destructive hostility toward Israel. The breaking of the staff is a prophetic sign-act of enormous gravity: the physical breaking enacts the theological reality of covenantal withdrawal.</p>",
    "11": "<p><strong>vattufar bayom hahu vedeu ken aniyei hatzon ha&rsquo;shomerim oti ki davar YHWH hu</strong>: &lsquo;It was canceled on that day. The sheep merchants who were watching understood that this was the word of the LORD.&rsquo; The recognition by the <em>aniyei hatzon ha&rsquo;shomerim</em> (the poor/afflicted ones of the flock who were watching) is significant — it is specifically the humble, attentive ones who recognize the prophetic sign-act as the word of YHWH. Those who recognized the shepherd&rsquo;s departure as divinely significant are the OT type of those who recognized Jesus as the fulfillment of the prophetic shepherd pattern.</p>",
    "12": "<p><strong>va&rsquo;omar alehem im tov be&rsquo;eineichem havu sechari ve&rsquo;im lo chadalu va&rsquo;ishqelu et sechari sheloshim keseph</strong>: &lsquo;I said to them, &ldquo;If you think it right, pay me my wages; if not, keep them.&rdquo; So they weighed out thirty pieces of silver.&rsquo; <em>Sheloshim keseph</em> (thirty pieces of silver) — the standard price for a slave (Exod 21:32: if an ox gores a slave, the owner pays thirty shekels of silver). The amount is insulting for a shepherd&rsquo;s wages — it is slave-compensation, not shepherd-pay. Matthew 26:15 and 27:3-10 cite this directly: Judas received thirty pieces of silver for betraying Jesus; when he returned it and it was thrown into the temple, the priests used it to buy the potter&rsquo;s field. Matthew attributes the quotation to Jeremiah (27:9) but the verbal echo of Zechariah 11:12-13 is unmistakable — a case of complex prophetic intertextuality.</p>",
    "13": "<p><strong>va&rsquo;yomer YHWH elai hashlichehu el hayotzer eder hayeqar asher yeqarti mealeihem va&rsquo;eqqach et sheloshim ha&rsquo;keseph va&rsquo;ashlich oto beit YHWH el hayotzer</strong>: &lsquo;But the LORD said to me, &ldquo;Throw it to the potter&rdquo; — this magnificent sum at which they valued me. So I took the thirty pieces of silver and threw them into the house of the LORD to the potter.&rsquo; The sarcastic phrase <em>eder hayeqar asher yeqarti mealeihem</em> (this magnificent/glorious price at which they valued me) drips with irony: thirty silver pieces as the &ldquo;magnificence&rdquo; of their assessment. The word <em>yotzer</em> (potter) and <em>otzar</em> (treasury) are acoustically similar in Hebrew, which may explain the LXX&rsquo;s reading &ldquo;into the treasury&rdquo; and Matthew&rsquo;s use of both words (Matt 27:6: thrown into the treasury; 27:10: given for the potter&rsquo;s field). The potter figure also echoes Jeremiah 18-19 (the potter&rsquo;s house as a place of divine reshaping and judgment).</p>",
    "14": "<p><strong>va&rsquo;egdod et maqeli ha&rsquo;sheni et Chovlim lehfer et ha&rsquo;achavah bein Yehudah uvein Yisrael</strong>: &lsquo;Then I broke my second staff called Union, canceling the bond of brotherhood between Judah and Israel.&rsquo; The breaking of the second staff — <em>Chovlim</em> (Union, the bond of brotherhood between Judah and Israel) — is the prophetic enactment of the final rupture between the northern and southern peoples. The &ldquo;bond of brotherhood&rdquo; (<em>ha&rsquo;achavah</em>) was already severed historically in 931 BCE and never fully healed; this breaking declares the theological cancellation of the covenantal unity that YHWH had maintained despite the political division. The restoration passages (Ezek 37:15-28: the two sticks joined; Zech 10:6-12: Judah and Joseph gathered together) represent the eschatological reversal of this broken union.</p>",
    "15": "<p>The second prophetic sign-act: YHWH commands the prophet to take the implements of a foolish shepherd. The contrast with the faithful shepherd of vv.4-14 is now explicit: after the rejected shepherd comes the foolish (<em>ewil</em>) shepherd. The sign-act models the coming of a leadership antithetical to YHWH&rsquo;s purpose — a shepherd who will prove worthless. The sequence of faithful shepherd rejected → foolish shepherd installed is the OT pattern for what happens when good leadership is despised: it is replaced by harmful leadership. This is the structural basis for the NT&rsquo;s contrast between Christ (the good shepherd, John 10:11) and the antichrist-shepherd (the man of lawlessness, 2 Thess 2:3-4).</p>",
    "16": "<p><strong>ki hineni maqim ro&rsquo;eh ba&rsquo;aretz hanichladot lo yifqod hanno&rsquo;arot lo yevaqesh uvehannivkeret lo yerape</strong>: &lsquo;For I am about to raise up a shepherd in the land who will not care for those that are perishing, or seek the young, or heal the injured.&rsquo; The anti-shepherd is defined by a series of negatives: will not visit the perishing (<em>lo yifqod</em> — not performing the visitation that is YHWH&rsquo;s characteristic action), not seek the straying, not heal the broken, not feed the healthy. He will instead eat the flesh of the fat sheep and tear off their hooves — exploitative, not protective. This is the anti-type of Christ&rsquo;s shepherd ministry: Jesus heals the injured (the blind, lame, sick throughout the Gospels), seeks the straying (Luke 15:4), feeds the healthy (the feeding of the 5,000), and gives his life rather than consuming the flock.</p>",
    "17": "<p><strong>hoy ro&rsquo;i ha&rsquo;elil ozoev hatzon cherev al zero&rsquo;o ve&rsquo;al ein yemino</strong>: &lsquo;Woe to the worthless shepherd who abandons the flock! May a sword strike his arm and his right eye! Let his arm be completely withered, his right eye totally blinded!&rsquo; The <em>ro&rsquo;i ha&rsquo;elil</em> (worthless/idol shepherd — <em>elil</em> meaning both &ldquo;worthless&rdquo; and &ldquo;idol/nothing&rdquo;) who abandons the flock receives the woe-curse: arm withered and eye blinded — the two primary tools of the shepherd (arm for strength, eye for watching). The arm that should protect is disabled; the eye that should guard is blinded. The anti-shepherd is judicially crippled in the organs that corresponded to his pastoral responsibility — the punishment fitting the crime of abandonment.</p>"
  },
  "12": {
    "1": "<p><strong>massa devar YHWH al Yisrael ne&rsquo;um YHWH noteh shamayim veyosed aretz veyotzer ruach adam beqirbo</strong>: &lsquo;An oracle — the word of the LORD concerning Israel. This is the declaration of the LORD, who stretched out the heavens, laid the earth&rsquo;s foundations, and formed the human spirit within a person.&rsquo; The introduction to the second major oracle-collection (chs. 12-14) establishes YHWH&rsquo;s authority through three creation acts: <em>noteh shamayim</em> (stretching out the heavens — cosmic), <em>yosed aretz</em> (founding/establishing the earth — geological), and <em>yotzer ruach adam beqirbo</em> (forming the human spirit within — anthropological). The three-level creation (heavens, earth, inner person) frames what follows as a declaration from the Creator who commands all three domains. The formation of the <em>ruach adam</em> (human spirit) by YHWH is the most intimate of the three — making the forthcoming divine action (pouring out the spirit of grace, v.10) both consistent with and the fulfillment of the Creator&rsquo;s ongoing formation of the human inner life.</p>",
    "2": "<p><strong>hineni sam et Yerushalayim saf ra&rsquo;al lechol ha&rsquo;ammim saviv vegam al Yehudah yihyeh bamatzor al Yerushalayim</strong>: &lsquo;I am going to make Jerusalem a cup that sends all the surrounding peoples reeling.&rsquo; <em>Saf ra&rsquo;al</em> (cup of reeling/staggering/trembling) — the cup of divine judgment that makes its drinkers stagger is the standard OT metaphor for overwhelming divine wrath poured out (Isa 51:17-23: the cup of staggering; Jer 25:15-17: the cup of the wine of wrath). Jerusalem herself becomes the cup — those who attack her find themselves intoxicated and incapacitated by the attempt. The dynamic is the active divine protection of Jerusalem through her very helplessness: what appears vulnerable becomes the instrument of the attackers&rsquo; undoing.</p>",
    "3": "<p><strong>vehayah vayom hahu asim et Yerushalayim even ma&rsquo;amasah lechol ha&rsquo;ammim</strong>: &lsquo;On that day I will make Jerusalem a heavy stone for all the nations. Everyone who tries to lift it will injure themselves severely.&rsquo; <em>Even ma&rsquo;amasah</em> (a burdensome/heavy stone for lifting) — the stone that is too heavy to lift, injuring those who strain to move it. The image shifts from the passive cup to the active burden: those who attempt to carry off or control Jerusalem find themselves injured by the very object they seek to possess. The stone image connects with Zechariah 3:9 (the stone with seven eyes) and Zechariah 10:4 (the cornerstone from Judah) — the stone theology running through Zechariah points ultimately to Christ as the cornerstone who becomes a stone of stumbling for those who reject him (1 Pet 2:6-8).</p>",
    "4": "<p><strong>bayom hahu ne&rsquo;um YHWH akeh chol sus batimahon verochhevo bishigaon</strong>: &lsquo;On that day, declares the LORD, I will strike every horse with panic and every rider with madness.&rsquo; The striking of horses and riders with panic (<em>timahon</em>) and madness (<em>shigaon</em>) is YHWH&rsquo;s use of psychological disorientation as a military weapon — the same divine strategy used at the Exodus (Exod 14:24: YHWH looked down on the Egyptian army and threw it into panic), at Jericho (Josh 6), and at Gideon&rsquo;s battle (Judg 7:22). YHWH does not need superior arms; he disables the enemy&rsquo;s arms through panic and confusion. The watchers over Jerusalem — <em>et beit Yehudah epqach</em> (I will open my eyes over the house of Judah) — are directly protected while their attackers are disabled.</p>",
    "5": "<p><strong>ve&rsquo;amru alufei Yehudah belibbam ametz li yoshevei Yerushalayim baYHWH tzvaot Eloheihem</strong>: &lsquo;Then the clans of Judah will say in their hearts, &ldquo;The inhabitants of Jerusalem draw their strength from the LORD of Hosts, their God.&rdquo;&rsquo; The internal recognition by Judah&rsquo;s clans — saying &ldquo;in their hearts&rdquo; rather than aloud — is the quiet dawning of understanding that Jerusalem&rsquo;s strength comes from YHWH, not from its own resources. The phrase <em>ametz li yoshevei Yerushalayim baYHWH tzvaot</em> (strength for me are the inhabitants of Jerusalem in/through YHWH of Hosts) is an affirmation of the source of covenantal security: not military alliance, not fortifications, but YHWH&rsquo;s direct protection of his city and people.</p>",
    "6": "<p><strong>bayom hahu asim et alufei Yehudah kecior esh be&rsquo;etzim uchapad esh bamer uachalufei saviv miyamin umissemol et kol ha&rsquo;ammim saviv</strong>: &lsquo;On that day I will make the clans of Judah like a fire pot among logs, like a flaming torch among sheaves. They will consume all the surrounding peoples on the right and on the left.&rsquo; The fire imagery — <em>cior esh be&rsquo;etzim</em> (fire pot among logs) and <em>chapad esh bamer</em> (flaming torch among sheaves) — is the OT image of irresistible and consuming divine-empowered warfare. The fuel that the surrounding nations provide for the fire of Judah is the reversal of their intended conquest: the attackers become the fuel for the defenders. The simultaneous right-and-left consuming ensures no escape route is left for the enemies of YHWH&rsquo;s people.</p>",
    "7": "<p><strong>vehoshi&rsquo;a YHWH et ohalei Yehudah barishonah</strong>: &lsquo;The LORD will save the settlements of Judah first, so that the prestige of the house of David and of Jerusalem&rsquo;s inhabitants does not become greater than that of Judah.&rsquo; The divine decision to save the rural settlements (<em>ohalei Yehudah</em>, tents/settlements of Judah) before the city is an egalitarian reversal of the usual priority order (cities before rural areas). YHWH deliberately prevents the elevation of the Jerusalem establishment over the rural communities — a theme consistent with the Prophets&rsquo; critique of urban centralization and the OT&rsquo;s concern for the periphery. The glory of the house of David and the city should not be magnified at the expense of the broader people.</p>",
    "8": "<p><strong>bayom hahu yagen YHWH be&rsquo;ad yoshev Yerushalayim vehayah hanichshal bahem bayom hahu keDavid</strong>: &lsquo;On that day the LORD will protect the inhabitants of Jerusalem; even the weakest among them will be like David on that day.&rsquo; The eschatological elevation of the weakest (<em>hanichshal</em>, the stumbler/weakest) to Davidic strength — and the house of David to divine/angelic status — is the escalating pattern of eschatological empowerment. The weakest inhabitant of Jerusalem becomes like David (the paradigmatic warrior-king); the house of David becomes like God/the Angel of the LORD (<em>ke-Elohim keMelach YHWH</em>). The elevation of the weakest is the OT form of the NT beatitude: &ldquo;the last will be first, and the first will be last&rdquo; (Matt 20:16).</p>",
    "9": "<p><strong>vehayah bayom hahu avaqesh lehashid et kol hagoyim haba&rsquo;im al Yerushalayim</strong>: &lsquo;On that day I will set out to destroy all the nations that attack Jerusalem.&rsquo; The divine declaration of purpose against the attacking nations — <em>avaqesh</em> (I will set out/seek) to destroy them — frames the entire eschatological battle as YHWH&rsquo;s active initiative, not a defensive reaction. The phrase is the transition from the protection of Jerusalem (vv.1-8) to the outpouring of the spirit (v.10): YHWH&rsquo;s decisive military action against the nations is the context within which the spiritual transformation of the house of David and Jerusalem (v.10) takes place. The outpouring of grace is not in spite of the judgment but alongside it.</p>",
    "11": "<p><strong>bayom hahu yigdal hamispod biYerushalayim kemispod Hadadrimmon beviqqat Megiddon</strong>: &lsquo;On that day the mourning in Jerusalem will be as intense as the mourning for Hadad-rimmon in the plain of Megiddo.&rsquo; <em>Hadadrimmon</em> — either a place name in the valley of Jezreel or a reference to the mourning for King Josiah, who was killed at Megiddo (2 Kgs 23:29-30; 2 Chr 35:24-25). The mourning for Josiah — the most beloved of Judah&rsquo;s kings, who died unexpectedly in battle — was the paradigmatic great mourning of OT history. Using it as the comparison for the mourning over the pierced one of v.10 signals the intensity and the grief-character of the mourning: this is not merely ritual mourning but the profound grief of a people who have recognized what they have done and lost.</p>",
    "12": "<p><strong>vesafedah ha&rsquo;aretz mishpachot mishpachot levad</strong>: &lsquo;The land will mourn, each family privately.&rsquo; The careful enumeration of mourning family by family — David, Nathan, Levi, Shimei, and all remaining families, each in private with men and women separated — is an elaboration that emphasizes the personal, individual, non-communal character of the mourning. The separation of men and women in mourning (vv.12-14) is unusual and may reflect the practices of deepest mourning (as in Joel 2:16: separate the bridegroom and bride). The individual, private mourning of each family is the NT form of personal conviction before God: &ldquo;they were cut to the heart and said to Peter and the rest of the apostles, Brothers, what shall we do?&rdquo; (Acts 2:37).</p>",
    "13": "<p><strong>mishpachat beit Levi levad vesheihem levad mishpachat Shimi levad vensheihem levad</strong>: &lsquo;The family of the house of Levi in private, with the women separately; the family of Shimei in private, with the women separately.&rsquo; The inclusion of the priestly tribe (Levi) in the mourning — even those whose official function would be to lead worship rather than mourn in private — underscores the universality and depth of the mourning. Shimei (a sub-branch of Levi, Num 3:17-21) is specifically named alongside Levi, and then &ldquo;all remaining families&rdquo; in v.14, ensuring that no clan or class escapes the mourning. The priestly families mourn like everyone else before the one they have pierced — there is no priestly exemption from personal grief over the rejection of the shepherd-king.</p>",
    "14": "<p><strong>kol hamishpachot hanish&rsquo;arot mishpachot mishpachot levad vensheihem levad</strong>: &lsquo;And all the remaining families, each in private, with the women separately.&rsquo; The closing verse of the mourning section confirms its universality by the phrase <em>kol hamishpachot</em> (all the families) — a totality encompassing every family in the land. The repeated formula &ldquo;in private, with the women separately&rdquo; functions as a liturgical refrain, its repetition emphasizing the thoroughness of the mourning. The universality of grief — every family, every individual, men and women alike — is the OT picture of the final mourning that Revelation 1:7 describes: &ldquo;every eye will see him, even those who pierced him, and all tribes of the earth will wail on account of him.&rdquo;</p>"
  },
  "13": {
    "1": "<p><strong>bayom hahu yihyeh maqor niftach leveit David uleyoshevei Yerushalayim lechatat uleNidah</strong>: &lsquo;On that day a fountain will be opened for the house of David and the inhabitants of Jerusalem to cleanse them from sin and impurity.&rsquo; <em>Maqor</em> (fountain/spring — a natural, flowing, perpetual source of water) contrasts with the cisterns and wells of the OT: a fountain is never depleted, fed by underground springs. <em>Chatat</em> (sin-offering/sin) and <em>nidah</em> (impurity — the ritual uncleanness of menstruation, used more broadly for severe uncleanness) define the two categories of defilement that the fountain cleanses: moral guilt and ritual uncleanness together. The opened fountain is the OT&rsquo;s image for the inexhaustible cleansing that the NT identifies as the blood of Christ: &ldquo;the blood of Jesus his Son cleanses us from all sin&rdquo; (1 John 1:7). John 7:38 (rivers of living water flowing from the believer) and Revelation 22:1 (the river of the water of life, clear as crystal) develop the fountain imagery further.</p>",
    "2": "<p><strong>vehayah bayom hahu ne&rsquo;um YHWH tzvaot akrit et shemot ha&rsquo;atzabim min ha&rsquo;aretz velo yizzachru od</strong>: &lsquo;On that day, declares the LORD of Hosts, I will remove the names of the idols from the land, so that they will no longer be remembered.&rsquo; The removal of the <em>shemot ha&rsquo;atzabim</em> (names of the idols) is more thorough than the removal of the physical idols: when the name is forgotten, the idol has no residual claim on memory or worship. The OT&rsquo;s concern for the names of false gods (Ps 16:4: I will not take their names on my lips; Exod 23:13: make no mention of the names of other gods) becomes the eschatological promise that the names themselves will be cut off. The NT equivalent: all names and powers subjected to Christ, so that only the name of Jesus retains ultimate honor (Phil 2:9-11: the name above every name).</p>",
    "3": "<p>The severity of the anti-prophecy law in the eschatological period: parents themselves pronounce the death sentence on a false prophet child. The parental judgment (<em>deqaruhu aviv ve&rsquo;immo</em>, his father and mother who bore him will pierce/stab him) uses the same verb <em>daqqar</em> (pierce/stab) as 12:10 (<em>asher daqaru</em>, whom they pierced) — the only two occurrences of this verb in Zechariah, creating a verbal link between the piercing of the shepherd-king and the piercing of false prophets. The eschatological community so values true prophecy over false that even family loyalty yields to prophetic accountability.</p>",
    "4": "<p><strong>vehayah bayom hahu yevoshu hanevi&rsquo;im ish mecheziyonato behinnabe&rsquo;o velo yilbeshu aderet se&rsquo;ar lema&rsquo;an kachassh</strong>: &lsquo;On that day every prophet will be ashamed of his prophetic vision, and they will no longer put on a hairy cloak in order to deceive.&rsquo; The hairy cloak (<em>adderet se&rsquo;ar</em>) was the distinctive garment of prophets — Elijah&rsquo;s mantle (2 Kgs 1:8: a man wearing a garment of hair), John the Baptist&rsquo;s clothing (Matt 3:4: his clothing was camel&rsquo;s hair). The false prophet who disguises himself in prophetic clothing is the OT precursor to Jesus&rsquo;s warning about false prophets who come in sheep&rsquo;s clothing (Matt 7:15) — the external prophetic costume used to claim an authority that is not authentic. In the eschatological era, the hairy cloak will no longer be used deceptively because the era of false prophecy is ended.</p>",
    "5": "<p><strong>ve&rsquo;amar lo navi anochi ki ish oved adamah anochi ki adam hiqnani mineurai</strong>: &lsquo;He will say, &ldquo;I am not a prophet. I am a farmer — someone has owned me as a servant since my youth.&rdquo;&rsquo; The former false prophet&rsquo;s disavowal of prophetic identity — claiming to be a mere farmer-servant — is the prophetic silence that marks the end of the prophetic era. The insistence on being <em>ish oved adamah</em> (a man who works the ground/a farmer) echoes Amos 7:14 (I am not a prophet, nor a prophet&rsquo;s son, but a herdsman) — Amos&rsquo;s authentic rejection of the prophetic title in a context where he nevertheless prophesied. The false prophet&rsquo;s claim to be merely a servant-farmer inverts Amos: Amos genuinely was a farmer but spoke truly; the false prophet genuinely was a &ldquo;prophet&rdquo; but now denies it to escape accountability.</p>",
    "6": "<p><strong>ve&rsquo;amar elav mah hamakkot ha&rsquo;eleh bein yadeycha ve&rsquo;amar asher hukkeiti beit me&rsquo;ahavai</strong>: &lsquo;When someone asks him, &ldquo;What are these wounds on your hands?&rdquo; he will answer, &ldquo;Wounds I received in the house of my friends/lovers.&rdquo;&rsquo; The wounds on the hands (<em>makkot ... bein yadeycha</em>) of the former false prophet — apparently from ecstatic prophetic self-wounding (1 Kgs 18:28: the Baal prophets cut themselves) — betray his prophetic past even when he denies it. His cover story (&ldquo;received in the house of my friends&rdquo;) is inadequate: the wounds on the hands are the mark of the ecstatic prophet. The NT has applied v.6 to Christ&rsquo;s nail-wounds — &ldquo;wounds in the house of my friends/lovers&rdquo; becoming Christ&rsquo;s wounds inflicted by those he loved — though this reading requires reading against the original context (where the speaker is a false prophet).</p>",
    "7": "<p><strong>cherev uri al ro&rsquo;i ve&rsquo;al gever amiti ne&rsquo;um YHWH tzvaot hach et haro&rsquo;i tefutzeyna hatzon</strong>: &lsquo;Awake, O sword, against my shepherd, against the man who is my associate, declares the LORD of Hosts. Strike the shepherd, and the sheep will be scattered.&rsquo; The most theologically dense verse in Zechariah 9-14. Two key terms: (1) <em>ro&rsquo;i</em> (my shepherd — YHWH&rsquo;s own shepherd, the one he sent and possesses); (2) <em>gever amiti</em> (the man who is my associate/fellow/equal — from <em>&lsquo;amith</em>, a word meaning &ldquo;fellow citizen, associate, one who shares one&rsquo;s standing&rdquo;). The shepherd is not merely YHWH&rsquo;s servant but YHWH&rsquo;s <em>amith</em> — a term of equality, not subordination. YHWH commands the sword against his own equal/associate — an act of incomprehensible self-sacrifice. Jesus cites this verse in Gethsemane (Matt 26:31): &ldquo;You will all fall away because of me this night, for it is written, I will strike the shepherd, and the sheep of the flock will be scattered.&rdquo; The scattering of the disciples is the NT fulfillment of the sheep-scattering that Zechariah predicted.</p>",
    "8": "<p><strong>vehayah lechol ha&rsquo;aretz ne&rsquo;um YHWH shnei chelakim bah yikaretu yigve&rsquo;u uhashelishi yivvater bah</strong>: &lsquo;Throughout the whole land, declares the LORD, two thirds shall be cut off and die, but one third will be left.&rsquo; The judgment proportions — two thirds destroyed, one third surviving — are the OT&rsquo;s most explicit statement of the remnant theology: judgment is not total destruction but pruning that leaves a faithful remainder. Ezekiel 5:1-12 uses a similar tripartite division of the hair (one third burned, one third struck with the sword, one third scattered to the wind). The survival of one third is not accidental or a concession to human resilience but YHWH&rsquo;s deliberate preservation of a covenant remnant through the purifying judgment.</p>",
    "9": "<p><strong>veheveti et hashelishit ba&rsquo;esh utzaraptim katzeref et hakesef uvechantem kivalchan et hazahav hu yiqra bishmi va&rsquo;ani e&rsquo;eneh oto amarti ammi hu vehu yomar YHWH Elohai</strong>: &lsquo;I will put that third through the fire and refine them as silver is refined, and test them as gold is tested. They will call on my name and I will answer them; I will say, &ldquo;They are my people,&rdquo; and they will say, &ldquo;The LORD is my God.&rdquo;&rsquo; The refining metaphor — fire as the purifying agent that removes dross from silver and impurities from gold — is the OT&rsquo;s standard image for covenantal purification through suffering (Isa 48:10; Mal 3:2-3; Ps 66:10). The result of the refining is the restoration of the covenant formula: <em>ammi hu</em> (they are my people) / <em>YHWH Elohai</em> (the LORD is my God). This formula, originally given at Sinai (Lev 26:12), broken by the exile (Hos 1:9: Lo-ammi = not my people), and now restored through the fire of refinement, is the covenant relationship fully recovered. The NT applies this restoration to the church: &ldquo;once you were not a people, but now you are God&rsquo;s people&rdquo; (1 Pet 2:10).</p>"
  }
}

def main():
    existing = load_comm('mkt-original', 'zechariah')
    merge_comm(existing, ZECHARIAH)
    save_comm('mkt-original', 'zechariah', existing)
    print('Zechariah 8-13 mkt-original written.')

if __name__ == '__main__':
    main()
